select v_1 as "o_year", v_2 as "mkt_share" from (select *, v_3 / v_4 as v_2 from (select v_5 as v_1, sum(case when v_6 = 'BRAZIL' then v_7 else cast(cast('0' as integer) as decimal(12,2)) end) as v_3, sum(v_7) as v_4 from (select *, cast(strftime('%Y', v_8) as integer) as v_5, v_9 * (cast('1' as integer) - v_10) as v_7 from (select * from (select * from (select * from (select * from (select * from (select * from (select * from (select * from (select "p_partkey" as v_11, "p_name" as v_12, "p_mfgr" as v_13, "p_brand" as v_14, "p_type" as v_15, "p_size" as v_16, "p_container" as v_17, "p_retailprice" as v_18, "p_comment" as v_19 from "part") s where v_15 = 'ECONOMY ANODIZED STEEL') l inner join (select "l_orderkey" as v_20, "l_partkey" as v_21, "l_suppkey" as v_22, "l_linenumber" as v_23, "l_quantity" as v_24, "l_extendedprice" as v_9, "l_discount" as v_10, "l_tax" as v_25, "l_returnflag" as v_26, "l_linestatus" as v_27, "l_shipdate" as v_28, "l_commitdate" as v_29, "l_receiptdate" as v_30, "l_shipinstruct" as v_31, "l_shipmode" as v_32, "l_comment" as v_33 from "lineitem") r on v_11 = v_21) l inner join (select "s_suppkey" as v_34, "s_name" as v_35, "s_address" as v_36, "s_nationkey" as v_37, "s_phone" as v_38, "s_acctbal" as v_39, "s_comment" as v_40 from "supplier") r on v_34 = v_22) l inner join (select * from (select "o_orderkey" as v_41, "o_custkey" as v_42, "o_orderstatus" as v_43, "o_totalprice" as v_44, "o_orderdate" as v_8, "o_orderpriority" as v_45, "o_clerk" as v_46, "o_shippriority" as v_47, "o_comment" as v_48 from "orders") s where v_8 between (date('1995-01-01')) and (date('1996-12-31'))) r on v_20 = v_41) l inner join (select "c_custkey" as v_49, "c_name" as v_50, "c_address" as v_51, "c_nationkey" as v_52, "c_phone" as v_53, "c_acctbal" as v_54, "c_mktsegment" as v_55, "c_comment" as v_56 from "customer") r on v_42 = v_49) l inner join (select "n_nationkey" as v_57, "n_name" as v_58, "n_regionkey" as v_59, "n_comment" as v_60 from "nation") r on v_52 = v_57) l inner join (select "n_nationkey" as v_61, "n_name" as v_6, "n_regionkey" as v_62, "n_comment" as v_63 from "nation") r on v_37 = v_61) l inner join (select * from (select "r_regionkey" as v_64, "r_name" as v_65, "r_comment" as v_66 from "region") s where v_65 = 'AMERICA') r on v_59 = v_64) s) s group by 1) s) s order by v_1
